Statement A
Integrating factor of $\frac{d y}{d x}+y=x^2=e^{\int 1 \cdot d x}=e^x$
Statement R
$$
\begin{aligned}
\frac{d y}{d x}+P(x) y &amp; =Q(x) \\
\operatorname{IF} &amp; =e^{\int P(x) d x}
\end{aligned}
$$
$\therefore$ Both statements $A$ and $B$ are true and statement $\mathrm{R} \Rightarrow \mathrm{A}$.

Given differential equation is
$$
\begin{array}{rlrl} 
&amp; &amp; \left(x+2 y^3\right) \frac{d y}{d x}=y^2 \\
\Rightarrow &amp; y^2 \frac{d x}{d y} &amp; =x+2 y^3 \Rightarrow &amp; \frac{d x}{d y}-\frac{x}{y^2}=2 y \\
\therefore &amp; &amp; I F &amp; =e^{\int-\frac{1}{y^2} d y}=e^{\frac{1}{y}}
\end{array}
$$

$$
\cos (x+y) \frac{d y}{d x}=1
$$
Put $x+y=V \Rightarrow 1+\frac{d y}{d x}=\frac{d V}{d x}$
$$
\begin{aligned}
& \therefore \cos \mathrm{V}\left(\frac{\mathrm{dV}}{\mathrm{dx}}-1\right)=1 \Rightarrow \cos \mathrm{V}\left(\frac{\mathrm{dV}}{\mathrm{dx}}\right)=1+\cos \mathrm{V} \\
& \therefore \int \frac{\cos \mathrm{V}}{1+\cos \mathrm{V}} \mathrm{dV}=\int \mathrm{dx} \\
& \therefore \int\left[\frac{1+\cos \mathrm{V}}{1+\cos \mathrm{V}}-\frac{1}{1+\cos \mathrm{V}}\right] \mathrm{dV} \\
& =\int \mathrm{dx} \Rightarrow \int \mathrm{dV}-\frac{1}{2} \int \sec ^2 \frac{\mathrm{V}}{2} \mathrm{dV}=\int \mathrm{dx}
\end{aligned}
$$
$$
\begin{aligned}
& \therefore \mathrm{V}-\frac{1}{2} \frac{\tan \left(\frac{\mathrm{V}}{2}\right)}{\left(\frac{1}{2}\right)}=\mathrm{x}+\mathrm{c} \Rightarrow \mathrm{V}-\tan \left(\frac{\mathrm{V}}{2}\right)=\mathrm{x}+\mathrm{c} \\
& \Rightarrow \mathrm{x}+\mathrm{y}-\tan \left(\frac{\mathrm{x}+\mathrm{y}}{2}\right)=\mathrm{x}+\mathrm{c} \\
& \mathrm{y}=\tan \left(\frac{\mathrm{x}+\mathrm{y}}{2}\right)+\mathrm{c}
\end{aligned}
$$

$$
\frac{d y}{d x}=\frac{x+y+1}{x+y-1}
$$
Put $x+y=v \Rightarrow 1+\frac{d y}{d x}=\frac{d v}{d x}$
$$
\begin{aligned}
& \therefore \frac{d v}{d x}-1=\frac{v+1}{v-1} \Rightarrow \frac{d v}{d x}=\frac{v+1}{v-1}+1=\frac{2 v}{v-1} \\
& \therefore \int \frac{(v-1) d v}{2 v}=\int d x \\
& \therefore \int \frac{1}{2} d V-\int \frac{1}{2 v} d v=\int d x=\frac{v}{2}-\frac{1}{2} \log |v|=x+c \\
& \therefore \frac{x+y}{2}-\frac{1}{2} \log |x+y|=x+c
\end{aligned}
$$
We have $\mathrm{x}=\frac{2}{3}, \mathrm{y}=\frac{1}{3}$
$$
\begin{aligned}
& \therefore \frac{1}{2}-\frac{1}{2} \log |1|=\frac{2}{3}+c \Rightarrow c=\frac{1}{2}-\frac{2}{3}=\frac{-1}{6} \\
& \therefore \frac{x+y}{2}-\frac{1}{2} \log |x+y|=x-\frac{1}{6}
\end{aligned}
$$
$\begin{aligned} & \therefore \frac{x+y}{2}-\frac{1}{2} \log |x+y|=x-\frac{1}{6} \\ & \therefore(x+y)-\log |x+y|=2 x-\frac{2}{6} \Rightarrow y-x+\frac{1}{3}=\log |x+y|\end{aligned}$

$$
\begin{aligned}
& \left(3 x y+y^2\right) d x+\left(x^2+x y\right) d y=0 \\
& \therefore \frac{d y}{d x}=-\frac{\left(3 x y+y^2\right)}{\left(x^2+x y\right)}
\end{aligned}
$$
Put $y=v x \Rightarrow \frac{d y}{d x}=v+x \frac{d v}{d x}$


$$
\begin{aligned}
& \therefore v+x \frac{d v}{d x}=-\frac{\left(3 v x^2+v^2 x^2\right)}{\left(x^2+v x^2\right)}=-\frac{3 v+v^2}{1+v} \\
& \therefore x \frac{d v}{d x}=-\frac{3 v+v^2}{1+v}-v=-\frac{\left(2 v^2+4 v\right)}{1+v}
\end{aligned}
$$


$$
\begin{aligned}
& \therefore \int \frac{1+v}{\left(2 v^2+4 v\right)} d v=\int \frac{-1}{x} d x \\
& \therefore \frac{1}{2} \int \frac{v+1}{v^2+2 v} d v=-\int \frac{d x}{x} \Rightarrow \frac{1}{4} \int \frac{2(v+1)}{v^2+2 v} d v=-\log x+\log c_1
\end{aligned}
$$


$$
\begin{aligned}
& \therefore \frac{1}{4} \log \left(\mathrm{v}^2+2 \mathrm{v}\right)+\log \mathrm{x}=\log \mathrm{c}_1 \Rightarrow \frac{1}{4} \log \left(\frac{\mathrm{y}^2}{\mathrm{x}^2}+\frac{2 \mathrm{y}}{\mathrm{x}}\right)+\log \mathrm{x}=\log \mathrm{c}_1 \\
& \therefore \frac{1}{4} \log \left(\frac{\mathrm{y}^2+2 \mathrm{xy}}{\mathrm{x}^2}\right)+\log \mathrm{x}=\log \mathrm{c}_1 \Rightarrow \log \left(\frac{\mathrm{y}^2+2 \mathrm{xy}}{\mathrm{x}^2}\right)+\log \mathrm{x}^4=4 \log \mathrm{c}_1 \\
& \therefore \log \left[\left(\frac{\mathrm{y}^2+2 \mathrm{xy}}{\mathrm{x}^2}\right)\left(\mathrm{x}^4\right)\right]=\log \mathrm{c}_1^4 \Rightarrow \log \left[\mathrm{x}^2\left(\mathrm{y}^2+2 \mathrm{xy}\right)\right]=\log \mathrm{c}_1^4 \\
& \therefore \mathrm{x}^2\left(\mathrm{y}^2+2 \mathrm{xy}\right)=\mathrm{c}
\end{aligned}
$$
